const SVG_NS = 'http://www.w3.org/2000/svg';

/**
 * Resolve an icon value to SVG path `d` strings.
 * Handles "lucide:name" format and legacy raw SVG paths.
 */
export function resolveIconPaths(value: string): string[] {
  if (!value) return [];
  if (value.startsWith('lucide:')) {
    const name = value.slice('lucide:'.length);
    return LUCIDE_PATHS[name] ?? [];
  }
  // Legacy: raw SVG path string
  return [value];
}

/**
 * Re-render the paths inside an SVG element from an icon value.
 * Clears existing path/circle/rect children and creates new path elements.
 */
export function renderIconIntoSvg(svgEl: SVGSVGElement | Element, value: string): void {
  const paths = resolveIconPaths(value);
  if (paths.length === 0) return;

  // Remove existing SVG shape children (path, circle, rect, line, polyline, polygon)
  const children = Array.from(svgEl.children);
  for (const child of children) {
    const tag = child.tagName.toLowerCase();
    if (['path', 'circle', 'rect', 'line', 'polyline', 'polygon', 'ellipse'].includes(tag)) {
      child.remove();
    }
  }

  // Create new path elements
  for (const d of paths) {
    const pathEl = document.createElementNS(SVG_NS, 'path');
    pathEl.setAttribute('d', d);
    pathEl.setAttribute('stroke-linecap', 'round');
    pathEl.setAttribute('stroke-linejoin', 'round');
    svgEl.appendChild(pathEl);
  }
}
